&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Given statement :&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;X&amp;nbsp;&amp;le;&amp;nbsp;P = M&amp;nbsp;&amp;le;&amp;nbsp;N&amp;nbsp;&amp;ge;&amp;nbsp;O &amp;gt; R = L &amp;gt; W&amp;nbsp;&amp;ge;&amp;nbsp;K&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Conclusions:&lt;/span&gt;&lt;/p&gt;

